  ('e81ed302-c55d-41cb-844f-94e5a6491137', 'KIMCHI-5073', 'Indomie Instant Mi Goreng Rendang Spicy Beef 5 x 80g', 'Indomie Instant Mi Goreng Rendang Spicy Beef in a pack of 5 x 80g for a delicious meal.', 'Indomie Instant Mi Goreng Rendang Spicy Beef 5 x 80g', 'Indomie Instant Mi Goreng Rendang Spicy Beef in a pack of 5 x 80g for a delicious meal.'),
  ('3e03e299-a72e-4a8a-8a32-db668ec85344', 'KIMCHI-5068', 'Wang Jjajang Noodles for Jjajangmyeon 453g', 'Wang Jjajang Noodles for Jjajangmyeon, 453g package, ideal for making traditional dishes.', 'Wang Jjajang Noodles for Jjajangmyeon 453g', 'Wang Jjajang Noodles for Jjajangmyeon, 453g package, ideal for making traditional dishes.'),
  ('a7f2f330-7574-46f7-933e-4807fe889c01', 'KIMCHI-3552', 'Asia Style Konjac Fettuccine 20 x 270g (whole carton)', 'Asia Style Konjac Fettuccine in a whole carton of 20 x 270g, suitable for various recipes.', 'Asia Style Konjac Fettuccine 20 x 270g (whole carton)', 'Asia Style Konjac Fettuccine in a whole carton of 20 x 270g, suitable for various recipes.')
), matched AS (
  SELECT
    p.salon_id,
    p.id AS template_id,
    s.slug,
    s.product_name,
    s.short_description,
    s.meta_title,
    s.meta_description
  FROM source s
  JOIN channels ch ON ch.slug = 'asiandeligo' AND ch.is_active = true
  JOIN products p ON p.id = s.template_id::uuid AND p.salon_id = ch.salon_id
  WHERE p.deleted_at IS NULL
), backup_insert AS (
  INSERT INTO asiandeligo_product_translations_backup_20260708
  SELECT pt.*
  FROM product_translations pt
  JOIN matched m ON m.template_id = pt.template_id AND m.salon_id = pt.salon_id
  WHERE pt.lang_id = 'en'
    AND NOT EXISTS (SELECT 1 FROM asiandeligo_product_translations_backup_20260708 b WHERE b.id = pt.id)
  RETURNING id
), upserted AS (
  INSERT INTO product_translations (
    id, salon_id, template_id, lang_id, product_name, short_description,
    meta_title, meta_description, created_at, updated_at
  )
  SELECT
    gen_random_uuid(),
    salon_id,
    template_id,
    'en',
    product_name,
    short_description,
    meta_title,
    meta_description,
    NOW(),
    NOW()
  FROM matched
  ON CONFLICT (template_id, lang_id) DO UPDATE SET
    product_name = EXCLUDED.product_name,
    short_description = EXCLUDED.short_description,
    meta_title = EXCLUDED.meta_title,
    meta_description = EXCLUDED.meta_description,
    updated_at = NOW()
  WHERE product_translations.salon_id = EXCLUDED.salon_id
  RETURNING template_id
)
SELECT
  (SELECT COUNT(*) FROM source) AS source_rows,
  (SELECT COUNT(*) FROM matched) AS matched_rows,
  (SELECT COUNT(*) FROM backup_insert) AS backed_up_rows,
  (SELECT COUNT(*) FROM upserted) AS upserted_rows;

-- Verify the printed counts after running. The backup table can be used to restore previous EN rows if needed.
COMMIT;
